CREATE DATABASE IF NOT EXISTS magasin_informatique;
USE magasin_informatique;

CREATE TABLE utilisateurs (
    id_utilisateur INT PRIMARY KEY AUTO_INCREMENT,
    email VARCHAR(100) NOT NULL UNIQUE,
    mot_de_passe VARCHAR(255) NOT NULL,
    nom_complet VARCHAR(150),
    date_creation DATETIME DEFAULT CURRENT_TIMESTAMP,
    seuil_notification INT DEFAULT 5,
    notifications_activees BOOLEAN DEFAULT 1,
    INDEX idx_email (email)
);

CREATE TABLE categories (
    id_categorie INT PRIMARY KEY AUTO_INCREMENT,
    nom_categorie VARCHAR(100) NOT NULL UNIQUE,
    description TEXT
);

CREATE TABLE produits (
    id_produit INT PRIMARY KEY AUTO_INCREMENT,
    reference VARCHAR(50) NOT NULL UNIQUE,
    designation VARCHAR(150) NOT NULL,
    description TEXT,
    marque VARCHAR(100),
    prix DECIMAL(10, 2) NOT NULL CHECK (prix > 0),
    quantite INT NOT NULL DEFAULT 0 CHECK (quantite >= 0),
    photo VARCHAR(255),
    id_categorie INT NOT NULL,
    date_creation DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (id_categorie) REFERENCES categories(id_categorie)
);







